import{_ as t,o as e,c as d,a2 as c}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"35 · 控制与模式：开会话时手里那块「调音台」","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/35-modes-and-control.md","filePath":"claude-code/35-modes-and-control.md"}'),s={name:"claude-code/35-modes-and-control.md"};function a(r,o,n,l,i,p){return e(),d("div",null,[...o[0]||(o[0]=[c('<h1 id="_35-·-控制与模式-开会话时手里那块「调音台」" tabindex="-1">35 · 控制与模式：开会话时手里那块「调音台」 <a class="header-anchor" href="#_35-·-控制与模式-开会话时手里那块「调音台」" aria-label="Permalink to &quot;35 · 控制与模式：开会话时手里那块「调音台」&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./34-cli-reference">34 CLI 参考手册：命令与全部标志</a> 帮你把「启动 Claude 之前」能拨的开关查全了。这一篇换到「会话已经开起来」之后——你跟 Claude 一来一回的过程里，手里其实攥着一整块「控制台」：怎么按一下就让它换工作模式、怎么让它先出方案别急着动手、怎么花钱换更快的响应、怎么用 Vim 手势编辑你的输入。<strong><a href="./20-permissions">第 20 篇</a>讲过权限那根缰绳，这一篇讲你手上的全套操纵杆。</strong></p></blockquote><p>兄弟们，咱们这一路下来，命令也会敲了、CLAUDE.md 也会写了、权限也配过了，按说该挺顺了。</p><p>可回头看，<strong>头一个月里浪费掉的时间，大半不在「不会用」，而在「不会控」</strong>——会话明明已经跑起来了，却只会干一件事：打字、回车、等。它输出跑偏了，傻等它跑完；它一上来就动手改文件，没拦住；明明该让它先出个方案的活儿，直接放它进去乱改一通。</p><p>说白了，<strong>Claude Code 的交互界面，远不止「输入框 + 回车」这么简单</strong>。它底下藏着一整套「会话内的控制手段」：一个键切换它的工作模式、一个键把它从跑偏里拽回来、一个命令让它先谋后动、还有花钱买速度的开关。这些东西<a href="./14-interface-and-shortcuts">第 14 篇</a>露过几个快捷键的脸，<a href="./20-permissions">第 20 篇</a>讲透了权限那一支，但「会话里到底能怎么操纵它」一直没有集中铺开过。</p><p>这么说吧：<strong>前面教的是「怎么让 Claude 干活」，这一篇教的是「干活过程中怎么实时操纵它」</strong>——像坐在调音台前，不是只会按播放，而是每一路推子都摸得到。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一张「会话内控制手段」全景图——哪个键管中断、哪个键管切模式、哪个键管换模型，一眼归位</li><li><code>Shift+Tab</code> 循环权限模式的全貌：默认三档之外的 <code>auto</code> / <code>bypassPermissions</code> / <code>dontAsk</code> 怎么进循环、谁排在谁前面（承接<a href="./20-permissions">第 20 篇</a>，不重讲权限规则）</li><li>Plan Mode（计划模式）不只是「一种权限模式」，更是一套「先出方案、你审完再动手」的工作流——什么时候该用、批准时那几个选项分别是啥</li><li>快速模式（fast mode）到底买的是什么、值不值、跟「努力级别」有啥区别</li><li>Vim 编辑模式怎么开、几个最实用的手势，以及一个能照着按的动手练习</li></ul><hr><h2 id="_01-先建个总框架-会话里你能拨的开关分三类" tabindex="-1">01 先建个总框架：会话里你能拨的开关分三类 <a class="header-anchor" href="#_01-先建个总框架-会话里你能拨的开关分三类" aria-label="Permalink to &quot;01 先建个总框架：会话里你能拨的开关分三类&quot;">​</a></h2><p>动手记快捷键之前，先在脑子里把「会话内的控制手段」归个类。<strong>它们不是一大把零散的键，而是分管三件不同的事。</strong> 类分清了，后面记起来就有挂钩。</p><p><strong>类比：坐在调音台前。</strong> 录音棚那块大台子上密密麻麻的推子和旋钮，看着唬人，其实就三类：一类管「这一路的音量大小」（推子），一类管「整段录还是停、回到哪一段重录」（走带键），一类管「音色怎么调」（均衡旋钮）。你不用全记，但得知道「想干这件事，手该往哪伸」。Claude Code 的会话控制也一样，<strong>三类开关各管一摊</strong>。</p><p>落到 Claude Code，这三类是：</p><ul><li><strong>管「它的自主权」</strong>——也就是权限模式：<code>Shift+Tab</code> 一键循环 <code>default</code> / <code>acceptEdits</code> / <code>plan</code>，决定它动手前问不问你（<a href="./20-permissions">第 20 篇</a>主讲）。</li><li><strong>管「它跑的过程」</strong>——中断与重定向：<code>Esc</code> 踩刹车、<code>Esc Esc</code> 倒车回退、<code>Ctrl+C</code> 中断或清输入、<code>Ctrl+B</code> 把任务丢后台。</li><li><strong>管「它怎么响应」</strong>——模型与速度：<code>Option+P</code> 换模型、<code>Option+T</code> 开关扩展思考、<code>/fast</code> 开关快速模式。</li></ul><p>并排放一张表，对照着看立刻清楚各管各的：</p><table tabindex="0"><thead><tr><th>你想干的事</th><th>伸手按</th><th>归哪一类</th></tr></thead><tbody><tr><td>让它动手前少问 / 多问点</td><td><code>Shift+Tab</code> 循环模式</td><td>管自主权</td></tr><tr><td>它跑偏了，喊停重新说</td><td><code>Esc</code></td><td>管过程</td></tr><tr><td>把整段对话退回上一个点</td><td><code>Esc</code> <code>Esc</code>（输入框空时）</td><td>管过程</td></tr><tr><td>中断当前操作 / 清空输入框</td><td><code>Ctrl+C</code></td><td>管过程</td></tr><tr><td>长命令丢后台接着干别的</td><td><code>Ctrl+B</code></td><td>管过程</td></tr><tr><td>临时换个模型来答</td><td><code>Option+P</code>（Win/Linux 是 <code>Alt+P</code>）</td><td>管响应</td></tr><tr><td>让它多想会儿 / 别想太久</td><td><code>Option+T</code></td><td>管响应</td></tr><tr><td>花钱买更快的 Opus</td><td><code>/fast</code> 或 <code>Option+O</code>（macOS）/ <code>Alt+O</code>（Win/Linux）</td><td>管响应</td></tr></tbody></table><blockquote><p>⚠️ <strong>macOS 用户先看这条</strong>：表里那些 <code>Option+</code> 开头的快捷键（<code>Option+P</code>、<code>Option+T</code>、<code>Option+O</code>），在 Mac 上多数需要先把终端的 Option 配成 Meta 键才生效——iTerm2 在「设置 → 配置文件 → 键」里把左/右 Option 设成「Esc+」，Apple Terminal 在「设置 → 配置文件 → 键盘」勾上「使用 Option 作为 Meta 键」。官方有个例外：从 v2.1.132 起，<code>Option+T</code>（切换扩展思考）在 Mac 上<strong>无需配置</strong>就能用。</p></blockquote><p>这张表你不用背，<strong>但「这事归哪一类」这个意识得有</strong>——想「让它少问」别去按 <code>Esc</code>，想「喊停」别去按 <code>Shift+Tab</code>，分清了就不会乱抓。</p><blockquote><p>💡 一句话总结：会话里的控制手段分三类——<strong>管自主权（<code>Shift+Tab</code>）、管过程（<code>Esc</code> / <code>Ctrl+C</code> / <code>Ctrl+B</code>）、管响应（<code>Option+P</code> / <code>/fast</code>）</strong>；记不住具体键不要紧，先记住「想干这事，手该往哪一类伸」。</p></blockquote><hr><h2 id="_02-管过程-esc-是刹车-esc-esc-是倒车" tabindex="-1">02 管过程：Esc 是刹车，Esc Esc 是倒车 <a class="header-anchor" href="#_02-管过程-esc-是刹车-esc-esc-是倒车" aria-label="Permalink to &quot;02 管过程：Esc 是刹车，Esc Esc 是倒车&quot;">​</a></h2><p>三类里头，<strong>最该先练熟的是「管过程」这一类</strong>，因为它救场最频繁。把最常用的几个挑出来，逐个说清「什么时候按、按下去发生啥」。</p><h3 id="esc-它跑偏了-一脚刹车" tabindex="-1">Esc：它跑偏了，一脚刹车 <a class="header-anchor" href="#esc-它跑偏了-一脚刹车" aria-label="Permalink to &quot;Esc：它跑偏了，一脚刹车&quot;">​</a></h3><p><code>Esc</code> 干一件事：<strong>停下 Claude 当前正在做的事</strong>——不管是它正在生成回答，还是正在调某个工具调到一半。按下去，它立刻停，然后把光标交还给你，等你重新发话。</p><p>关键是官方这句让人安心的话：</p><blockquote><p>停止当前响应或工具调用中途，以便您可以重定向。Claude 保留迄今为止完成的工作。</p></blockquote><p>也就是说，<strong><code>Esc</code> 不是「撤销」，是「暂停 + 交还方向盘」</strong>。它已经做完的部分（比如已经读完的文件、已经写好的半个函数）都留着，你只是打断它接下来的动作，改个方向让它继续。</p><p>最常用 <code>Esc</code> 的场景：让它改个小功能，结果它领会偏了，吭哧吭哧开始大改五六个文件。要是傻等它跑完再纠正，白白浪费它好几分钟的输出；学乖的做法是——<strong>一看方向不对，立刻 <code>Esc</code>，然后补一句「停，我只要改 <code>login.js</code> 那一个函数，别动别的」</strong>，它当场掉头。这一个键，重度使用下每天保守得按几十次。</p><h3 id="esc-esc-把对话退回上一个点" tabindex="-1">Esc Esc：把对话退回上一个点 <a class="header-anchor" href="#esc-esc-把对话退回上一个点" aria-label="Permalink to &quot;Esc Esc：把对话退回上一个点&quot;">​</a></h3><p>连按两下 <code>Esc</code>，行为分两种，<strong>取决于你输入框里有没有字</strong>：</p><ul><li><strong>输入框里有字</strong>：双 <code>Esc</code> 清空它，并把这段草稿存进历史，等会儿按 <code>↑</code> 还能调回来。</li><li><strong>输入框是空的</strong>：双 <code>Esc</code> 打开<strong>回退菜单</strong>——让你从对话里上一个节点恢复，或者总结一下代码和对话。</li></ul><p>第二种就是「倒车」：<strong>把整段对话退回到之前某个状态</strong>。这块属于检查点（checkpoint）的范畴，<a href="./37-checkpoints">第 37 篇</a>专门讲，这里你先记住一个动作：<strong>输入框空着的时候双击 <code>Esc</code>，能掀开「回到上一个存档点」的菜单</strong>。返工的时候常用——感觉「最近这几轮把事情带沟里了」，双 <code>Esc</code> 退回到沟之前那个干净点，重新开口。</p><h3 id="ctrl-c-和-ctrl-d-别再当退出键瞎按" tabindex="-1">Ctrl+C 和 Ctrl+D：别再当退出键瞎按 <a class="header-anchor" href="#ctrl-c-和-ctrl-d-别再当退出键瞎按" aria-label="Permalink to &quot;Ctrl+C 和 Ctrl+D：别再当退出键瞎按&quot;">​</a></h3><p>这俩新手最容易混，一条条钉死：</p><ul><li><strong><code>Ctrl+C</code></strong>：有操作在跑就<strong>中断它</strong>；没有操作在跑，第一次按<strong>清空输入框</strong>，<strong>再按一次才退出</strong> Claude Code。</li><li><strong><code>Ctrl+D</code></strong>：直接<strong>退出</strong> Claude Code 会话（EOF 信号）。</li></ul><p>这里有个容易踩的小坑：想清空输入框里打了一半的字，顺手 <code>Ctrl+C</code> 一下，没反应又来一下——结果直接把会话退了。原因在于，<strong>空输入框上的第二下 <code>Ctrl+C</code> 是退出</strong>。所以清输入框宁可用 <code>Ctrl+U</code>（从光标删到行首）或者干脆 <code>Esc Esc</code>，不轻易连按 <code>Ctrl+C</code>。</p><h3 id="ctrl-b-长命令丢后台-别干等" tabindex="-1">Ctrl+B：长命令丢后台，别干等 <a class="header-anchor" href="#ctrl-b-长命令丢后台-别干等" aria-label="Permalink to &quot;Ctrl+B：长命令丢后台，别干等&quot;">​</a></h3><p>这个救场也猛。Claude 跑一条要很久的命令时（装依赖、跑构建、起开发服务器），你不必干等——<strong>按 <code>Ctrl+B</code> 把它丢到后台</strong>，Claude 立刻腾出手来响应你的新指令，那条命令在后台接着跑，输出写进文件，它需要时再读回来。</p><blockquote><p>用 tmux 的兄弟注意：tmux 自己的前缀键也是 <code>Ctrl+B</code>，所以在 tmux 里得<strong>按两下</strong>才能把任务丢后台。这个点很容易被坑，记牢。</p></blockquote><table tabindex="0"><thead><tr><th>键</th><th>一句话作用</th><th>最容易记错的点</th></tr></thead><tbody><tr><td><code>Esc</code></td><td>喊停 + 重定向，已完成的保留</td><td>不是撤销，是暂停交还方向盘</td></tr><tr><td><code>Esc</code> <code>Esc</code></td><td>输入框空时打开回退菜单</td><td>有字时是清空草稿，行为不同</td></tr><tr><td><code>Ctrl+C</code></td><td>中断操作 / 清输入 / 再按退出</td><td>空输入框第二下就退了</td></tr><tr><td><code>Ctrl+D</code></td><td>直接退出会话</td><td>一下就退，别当中断键</td></tr><tr><td><code>Ctrl+B</code></td><td>长命令丢后台</td><td>tmux 里要按两下</td></tr></tbody></table><blockquote><p>💡 一句话总结：<strong><code>Esc</code> 是刹车（跑偏就拽回来）、<code>Esc Esc</code> 是倒车（退回上一个点）、<code>Ctrl+C</code> 别乱连按（空框第二下就退）、长命令用 <code>Ctrl+B</code> 丢后台</strong>——这四下练成肌肉记忆，会话里就再也不会干等或误退了。</p></blockquote><hr><h2 id="_03-管自主权-shift-tab-循环模式的完整版" tabindex="-1">03 管自主权：Shift+Tab 循环模式的完整版 <a class="header-anchor" href="#_03-管自主权-shift-tab-循环模式的完整版" aria-label="Permalink to &quot;03 管自主权：Shift+Tab 循环模式的完整版&quot;">​</a></h2><p>权限模式那张「从严到松」的光谱，<a href="./20-permissions">第 20 篇</a>已经讲透了——<code>default</code> 步步问、<code>acceptEdits</code> 改码免问、<code>plan</code> 只看不动、<code>auto</code> 有分类器兜底、<code>bypassPermissions</code> 完全裸奔、<code>dontAsk</code> 只认预批准。<strong>这一节不重讲它们各是啥（忘了回去翻<a href="./20-permissions">第 20 篇</a>），只补一件那篇没细抠的事：<code>Shift+Tab</code> 这个循环，到底怎么转。</strong></p><p>先把基本盘立住：<strong>会话里随手按 <code>Shift+Tab</code>，在三种模式间转圈</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>default → acceptEdits → plan → （再按回到 default）</span></span></code></pre></div><p>当前是哪档，看状态栏。比如切到 <code>acceptEdits</code>，状态栏会亮 <code>⏵⏵ accept edits on</code>。这是默认循环，<strong>只有这三档</strong>。</p><p>那 <code>auto</code>、<code>bypassPermissions</code>、<code>dontAsk</code> 去哪了？<strong>它们不在默认循环里，得满足条件或带参数才会被「插」进来。</strong> 官方把规则写得很细，我给你翻译成人话：</p><ul><li><strong><code>auto</code>（自动模式）</strong>：当你的账户满足 auto mode 的全部要求时，它才出现在循环里。第一次循环到它，会弹一个「选择加入」提示，你点同意它才正式入列；要是你选「不，不再询问」，它就被踢出循环。</li><li><strong><code>bypassPermissions</code>（跳过一切检查）</strong>：只有你用 <code>--permission-mode bypassPermissions</code>、<code>--dangerously-skip-permissions</code> 或 <code>--allow-dangerously-skip-permissions</code> 启动之后，它才出现。注意 <code>--allow-</code> 那个变体只是<strong>把它加进循环但不立刻激活</strong>。</li><li><strong><code>dontAsk</code>（只认预批准）</strong>：<strong>永远不进循环</strong>，只能用 <code>--permission-mode dontAsk</code> 启动时指定。</li></ul><p>更细的一条，官方明确了<strong>插队的位置</strong>，免得你按到一半发现顺序不对：</p><blockquote><p>启用的可选模式在 <code>plan</code> 之后插入，<code>bypassPermissions</code> 优先，<code>auto</code> 最后。如果您同时启用了两者，您将在前往 <code>auto</code> 的途中循环通过 <code>bypassPermissions</code>。</p></blockquote><p>把这句翻成你按键时的实际体验：假设你两个都启用了，那一圈 <code>Shift+Tab</code> 转下来是这样的——</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>default → acceptEdits → plan → bypassPermissions → auto → （回到 default）</span></span></code></pre></div><p><code>auto</code> 永远排在最后一个，<code>bypassPermissions</code> 在它前面。<strong>记住这个顺序，你就知道再按几下能到你要的那档</strong>，不用瞎转。</p><p>推荐的实操习惯，跟<a href="./20-permissions">第 20 篇</a>说的一致——<strong>绝大多数时候只在默认三档里 <code>Shift+Tab</code> 手动切</strong>：接陌生项目先切 <code>plan</code> 让它通读出方案，信得过方向了切 <code>acceptEdits</code> 放它改，改完想严一点再切回 <code>default</code>。<code>bypassPermissions</code> 只在隔离容器里用启动参数开，别挂进日常循环——这道红线<a href="./20-permissions">第 20 篇</a>画过，不重复了。</p><blockquote><p>💡 一句话总结：<code>Shift+Tab</code> 默认只在 <strong><code>default</code> / <code>acceptEdits</code> / <code>plan</code></strong> 三档转；<code>auto</code> / <code>bypassPermissions</code> 要满足条件或带启动参数才入列，顺序是 <strong>「<code>plan</code> 之后，<code>bypassPermissions</code> 在前、<code>auto</code> 垫底」</strong>——记住这个排位，按几下心里就有数。</p></blockquote><hr><h2 id="_04-plan-mode-不止是一种模式-是一套「先谋后动」的工作流" tabindex="-1">04 Plan Mode：不止是一种模式，是一套「先谋后动」的工作流 <a class="header-anchor" href="#_04-plan-mode-不止是一种模式-是一套「先谋后动」的工作流" aria-label="Permalink to &quot;04 Plan Mode：不止是一种模式，是一套「先谋后动」的工作流&quot;">​</a></h2><p>上一节把 <code>plan</code> 当作循环里的一档一笔带过，但它值得单开一节——<strong>因为 Plan Mode 的真正价值，不在「它是种只读模式」，而在它背后那套「先出方案、你审完再动手」的完整工作流。</strong> 这是用得最频繁、也最推荐小白尽早养成习惯的一个控制手段。</p><p><strong>类比：导演喊「先走一遍戏」。</strong> 正式开拍前，导演经常让演员先彩排一遍——走位、台词、节奏全过一遍，但<strong>不开机、不消耗胶片</strong>。看着没问题了，才喊「开机，实拍」。Plan Mode 就是这个「走戏」环节：<strong>Claude 把整件事在脑子里走一遍，读文件、做调研、写出「我打算这么改」的方案，但一个字都不真动你的源码</strong>；你看完点头，它才「实拍」开始改。</p><p>官方把它的行为界定得很清楚：</p><blockquote><p>Plan mode 告诉 Claude 研究并提议更改而不进行更改。Claude 读取文件、运行 shell 命令进行探索，并编写计划，但不编辑您的源代码。</p></blockquote><h3 id="怎么进、怎么出" tabindex="-1">怎么进、怎么出 <a class="header-anchor" href="#怎么进、怎么出" aria-label="Permalink to &quot;怎么进、怎么出&quot;">​</a></h3><p>进 Plan Mode 有两条路：</p><ul><li><strong><code>Shift+Tab</code> 循环到 <code>plan</code></strong>——管整段会话，直到你切走。</li><li><strong>单条提示前加 <code>/plan</code></strong>——只让这一条提示走计划模式，适合「就这一件事我想先看方案」。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plan 帮我把用户登录从 session 改成 JWT，先别动，告诉我你打算怎么改</span></span></code></pre></div><p>想中途退出而<strong>不批准</strong>计划？再按一次 <code>Shift+Tab</code> 循环走就行。</p><h3 id="方案出来了-批准时那几个选项是啥" tabindex="-1">方案出来了，批准时那几个选项是啥 <a class="header-anchor" href="#方案出来了-批准时那几个选项是啥" aria-label="Permalink to &quot;方案出来了，批准时那几个选项是啥&quot;">​</a></h3><p>这是 Plan Mode 最有「工作流」味道的一步，也是新手最容易懵的地方。当 Claude 把方案写好，它会停下来问你「接下来怎么办」，给的选项大致是这几个：</p><ul><li><strong>批准并在 auto mode 中启动</strong>——你完全信方向，放它自动干到底。</li><li><strong>批准并接受编辑</strong>——切到 <code>acceptEdits</code>，改码免问，但危险命令还会停。</li><li><strong>批准并手动审查每个编辑</strong>——回到 <code>default</code> 那种步步确认。</li><li><strong>继续规划并给反馈</strong>——方案还不够好，你提意见让它再改方案。</li></ul><p><strong>看明白没有？批准计划这一下，等于「同时选定了接下来用哪种权限模式」。</strong> 它退出 Plan Mode，直接把会话切到你选的那档，然后开始动手。这就是为什么说 Plan Mode 不是孤立一档，而是串起整条「探索 → 出方案 → 选自主权 → 动手」流程的枢纽。</p><p>还有两个官方给的细节，挺实用：</p><ul><li><strong><code>Ctrl+G</code> 直接编辑方案</strong>：方案写出来了，但你想亲手改两笔（比如「这一步删掉，顺序换一下」），按 <code>Ctrl+G</code> 在你的默认文本编辑器里打开它，改完再让 Claude 照着干。</li><li><strong>批准会自动给会话命名</strong>：除非你已经用 <code>--name</code> 或 <code>/rename</code> 起过名，否则批准计划时它会<strong>照方案内容自动命名这个会话</strong>，以后 <code>/resume</code> 找起来方便。</li></ul><h3 id="一个典型用法" tabindex="-1">一个典型用法 <a class="header-anchor" href="#一个典型用法" aria-label="Permalink to &quot;一个典型用法&quot;">​</a></h3><p>说白了，<strong>接任何一个不熟的项目，第一件事就是切 Plan Mode 让它通读一遍、出个方案。</strong> 比如接手一份别人留下的老代码，几万行，啥都不懂。直接 <code>Shift+Tab</code> 到 <code>plan</code>，扔一句「通读这个项目，告诉我整体结构和你建议从哪改起」。它读了一圈、列了份结构 + 改造建议，看完才能心里有底地放它进去。<strong>要是一上来就 <code>acceptEdits</code> 让它瞎改，大概率是一场灾难。</strong> 这个习惯，强烈建议你尽早养成。</p><blockquote><p>💡 一句话总结：Plan Mode 是「<strong>先走戏后实拍</strong>」——它只研究、只出方案、不动源码；批准方案那一下会<strong>顺带选定接下来的权限模式</strong>（auto / acceptEdits / 手动审查），<code>Ctrl+G</code> 还能让你亲手改方案。接陌生项目先 <code>/plan</code>，稳得多。</p></blockquote><hr><h2 id="_05-快速模式-fast-mode-花钱买的是速度-不是质量" tabindex="-1">05 快速模式（fast mode）：花钱买的是速度，不是质量 <a class="header-anchor" href="#_05-快速模式-fast-mode-花钱买的是速度-不是质量" aria-label="Permalink to &quot;05 快速模式（fast mode）：花钱买的是速度，不是质量&quot;">​</a></h2><blockquote><p>⚠️ <strong>研究预览功能，可能变化</strong>：fast mode 目前是研究预览版，功能、定价、可用性都可能随时调整；且要求 Claude Code v2.1.36 或更高版本。</p></blockquote><p>讲完「怎么控方向」，再讲一个「控速度」的开关——快速模式。先把最容易误解的一点摆正：</p><p><strong>快速模式不是换了个更强的模型，它换的是同一个 Opus 的「跑法」。</strong> 官方说得很直接：</p><blockquote><p>快速模式不是一个不同的模型。它使用 Claude Opus，但采用不同的 API 配置，优先考虑速度而不是成本效率。您获得相同的质量和功能，只是响应速度更快。</p></blockquote><p>具体快多少、贵多少？官方给的数字：<strong>最多快 2.5 倍</strong>，代价是每个 token 更贵。它只在 Opus 4.8 / 4.7 / 4.6 上支持，Sonnet、Haiku 用不了（⚠️ Opus 4.6 的快速模式已弃用，建议用 4.7 或 4.8）。</p><h3 id="怎么开" tabindex="-1">怎么开 <a class="header-anchor" href="#怎么开" aria-label="Permalink to &quot;怎么开&quot;">​</a></h3><p>就一个命令：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/fast</span></span></code></pre></div><p>输入 <code>/fast</code> 按 Tab 键打开或关闭。开了之后：</p><ul><li>如果你当时用的是别的模型，<strong>它会自动切到 Opus</strong>。</li><li>你会看到提示 <code>Fast mode ON</code>，提示框旁边冒出一个小 <code>↯</code> 图标。</li><li>随时再 <code>/fast</code> 一下，能查当前是开还是关。</li></ul><p>有个反直觉的点要记牢：<strong>关掉快速模式后，你还停在 Opus 上，模型不会自动切回你原来那个</strong>。想换回别的模型，得自己 <code>/model</code>。</p><h3 id="值不值-看你这会儿缺速度还是缺钱" tabindex="-1">值不值：看你这会儿缺速度还是缺钱 <a class="header-anchor" href="#值不值-看你这会儿缺速度还是缺钱" aria-label="Permalink to &quot;值不值：看你这会儿缺速度还是缺钱&quot;">​</a></h3><p>到底啥时候开？官方给的判断和实际体感一致——<strong>看你这个任务「延迟」和「成本」哪个更要命</strong>：</p><table tabindex="0"><thead><tr><th>场景</th><th>开快速模式？</th><th>为啥</th></tr></thead><tbody><tr><td>实时调 bug、快速迭代、赶 deadline</td><td>✅ 开</td><td>你在等它，慢一秒都难受，速度优先</td></tr><tr><td>长时间自主任务、批处理、CI/CD</td><td>❌ 不开</td><td>没人盯着，慢点无所谓，省钱优先</td></tr><tr><td>成本敏感的活儿</td><td>❌ 不开</td><td>每 token 更贵，堆起来肉疼</td></tr></tbody></table><p>还有一条<strong>省钱的关键细节</strong>，官方反复强调，也很容易踩：</p><blockquote><p>为了获得最佳成本效率，在会话开始时启用快速模式，而不是在对话中途切换。</p></blockquote><p>为啥？因为<strong>第一次开快速模式时，你要为「整个对话上下文」付一次完整的快速模式输入费</strong>。对话拖得越长再开，那一下越贵。所以<strong>要开就一开始开</strong>，别等聊了半天、上下文一大坨了才想起来开。这一下很容易交学费——一个聊了很久的会话中途开 fast，账单上那一下会明显比预期高。</p><h3 id="别和「努力级别」搞混" tabindex="-1">别和「努力级别」搞混 <a class="header-anchor" href="#别和「努力级别」搞混" aria-label="Permalink to &quot;别和「努力级别」搞混&quot;">​</a></h3><p>最后澄清一个常见混淆：快速模式 ≠ 调努力级别。这俩都影响速度，但路子完全不同：</p><table tabindex="0"><thead><tr><th>设置</th><th>干了啥</th><th>副作用</th></tr></thead><tbody><tr><td><strong>快速模式</strong></td><td>同样的模型质量，更低延迟</td><td>更贵</td></tr><tr><td><strong>调低努力级别</strong></td><td>让它少想点，更快出</td><td>复杂任务上质量可能掉</td></tr></tbody></table><p>一句话：<strong>快速模式不牺牲质量、只多花钱；调低努力级别是少思考、可能牺牲质量。</strong> 俩还能叠着用——简单任务上「快速模式 + 低努力级别」，速度拉满。</p><blockquote><p>⚠️ <strong>订阅用户额外注意</strong>：对 Pro/Max/Team/Enterprise 订阅用户，快速模式<strong>只走「使用额度」、不含在订阅速率限制里</strong>，从第一个 token 起就按快速模式费率单独计费。换句话说，它是要额外掏钱的，不是订阅白送的。开之前心里有数。</p></blockquote><blockquote><p>💡 一句话总结：快速模式买的是<strong>同一个 Opus 的速度（最多 2.5 倍），代价是更贵</strong>；<code>/fast</code> 开关，<strong>要开就会话一开始开</strong>（中途开那一下更贵）；赶时间就开、跑长任务就关，别和「调努力级别」混为一谈。</p></blockquote><hr><h2 id="_06-vim-编辑模式-给你的输入框装上老司机手势" tabindex="-1">06 Vim 编辑模式：给你的输入框装上老司机手势 <a class="header-anchor" href="#_06-vim-编辑模式-给你的输入框装上老司机手势" aria-label="Permalink to &quot;06 Vim 编辑模式：给你的输入框装上老司机手势&quot;">​</a></h2><p>最后一个控制手段，服务的是「你怎么编辑自己打的字」——Vim 模式。<strong>如果你压根没用过 Vim，这一节可以扫一眼就跳过，它不影响你用 Claude Code；但你要是 Vim 老手，开了它输入体验会顺手得多。</strong></p><p>Claude Code 的输入框默认是普通文本框（随便打字、方向键移动）。开了 Vim 模式，它就有了 Vim 那套「两种状态」：</p><ul><li><strong>INSERT（插入）模式</strong>：跟普通输入框一样，打字就是打字。</li><li><strong>NORMAL（普通）模式</strong>：键不再是字符，而是「命令」——<code>h/j/k/l</code> 移光标、<code>dd</code> 删一行、<code>w</code> 跳下一个词、<code>0</code> 跳行首、<code>$</code> 跳行尾……Vim 那套全套搬过来了。</li></ul><h3 id="怎么开-1" tabindex="-1">怎么开 <a class="header-anchor" href="#怎么开-1" aria-label="Permalink to &quot;怎么开&quot;">​</a></h3><p>通过 <code>/config</code> 菜单，找到「编辑器模式（Editor mode）」，切成 vim 即可。开了之后：</p><ul><li>按 <code>Esc</code> 进 NORMAL 模式（这时候按键是命令）。</li><li>按 <code>i</code> / <code>a</code> / <code>o</code> 等回到 INSERT 模式开始打字。</li></ul><p>下面几个是输入框里用得最多的，给完全没接触过的兄弟感受一下：</p><table tabindex="0"><thead><tr><th>在 NORMAL 模式按</th><th>干啥</th></tr></thead><tbody><tr><td><code>dd</code></td><td>删掉整行（比如想重写这条提示）</td></tr><tr><td><code>cw</code></td><td>改掉当前这个词</td></tr><tr><td><code>0</code> / <code>$</code></td><td>跳到行首 / 行尾</td></tr><tr><td><code>u</code></td><td>撤销刚才那下改动</td></tr><tr><td><code>i</code> / <code>a</code></td><td>在光标前 / 后开始插入打字</td></tr></tbody></table><p>有个 Vim 老手会喜欢的细节：<strong>在 NORMAL 模式下，如果光标已经在输入的最顶或最底、没法再往上/往下移了，这时按 <code>j</code>/<code>k</code> 或方向键，会去翻命令历史。</strong> 等于「移动」和「翻历史」无缝接上了。</p><p>说句实话，<strong>这个模式纯属「锦上添花」</strong>。Vim 重度用户开了它编辑长提示确实爽；但对不少小白来说压根没必要碰——普通文本框配上第 02 节那几个快捷键（<code>Ctrl+U</code> 删到行首、<code>Ctrl+W</code> 删词）已经够用了。<strong>所以：是 Vim 党就开，不是就别折腾，这不是必修课。</strong></p><blockquote><p>💡 一句话总结：Vim 模式给输入框装上 NORMAL/INSERT 两态和全套 Vim 手势，<code>/config</code> → 编辑器模式开启；<strong>Vim 老手开了顺手，纯新手完全可以跳过</strong>，不影响任何功能。</p></blockquote><hr><h2 id="_07-动手-把这套控制手段连起来跑一遍" tabindex="-1">07 动手：把这套控制手段连起来跑一遍 <a class="header-anchor" href="#_07-动手-把这套控制手段连起来跑一遍" aria-label="Permalink to &quot;07 动手：把这套控制手段连起来跑一遍&quot;">​</a></h2><p>光看不练记不住。下面给你设计一个<strong>5 分钟、不依赖任何复杂项目</strong>的练习，把本篇几个核心控制手段串起来按一遍，每步都给「预期看到啥」，你照着走、对照验证。</p><p>随便找一个空目录，<code>claude</code> 启动，然后：</p><p><strong>第一步：练 <code>Shift+Tab</code> 切模式，盯状态栏</strong></p><p>启动后，连续按几下 <code>Shift+Tab</code>，<strong>眼睛盯着状态栏</strong>。</p><blockquote><p><strong>预期</strong>：状态栏文字在三档之间循环变化——切到 <code>acceptEdits</code> 时显示类似 <code>⏵⏵ accept edits on</code>，切到 <code>plan</code> 时显示计划模式提示，转一圈回到默认（状态栏那行模式提示消失或显示默认）。<strong>确认你能靠状态栏认出当前在哪档</strong>。</p></blockquote><p><strong>第二步：进 Plan Mode，让它出个方案（但别真动）</strong></p><p><code>Shift+Tab</code> 切到 <code>plan</code>，然后输入一个会触发它「想动手」的请求：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在当前目录创建一个 hello.txt，里面写一行 &quot;hi from claude&quot;</span></span></code></pre></div><blockquote><p><strong>预期</strong>：它<strong>不会真的创建文件</strong>，而是给你一段「我打算这么做」的说明，末了停下来问你怎么继续（批准并接受编辑 / 手动审查 / 继续规划……）。<strong>确认目录里此刻并没有 <code>hello.txt</code></strong>——这就是 Plan Mode「只走戏不实拍」。</p></blockquote><p><strong>第三步：批准方案，观察它切了模式</strong></p><p>在它给的选项里，选「批准并接受编辑」（或手动审查那项）。</p><blockquote><p><strong>预期</strong>：它退出 Plan Mode，<strong>状态栏切到了你选的那档</strong>（选了接受编辑就显示 <code>accept edits on</code>），然后真的把 <code>hello.txt</code> 创建出来。<strong>确认这时目录里有了文件</strong>，且模式已经从 <code>plan</code> 变成你批准时选的那个——亲眼看一遍「批准计划 = 顺带选定权限模式」。</p></blockquote><p><strong>第四步：练 <code>Esc</code> 喊停</strong></p><p>再给它派一个稍微长点的活儿（比如「把这个目录下所有文件逐个读一遍并总结」），在它跑起来的当口，<strong>按一下 <code>Esc</code></strong>。</p><blockquote><p><strong>预期</strong>：它<strong>当场停下</strong>，把控制权交还给你，光标回到输入框。它已经做完的部分（比如已经读了的文件）保留着。你可以紧接着补一句新指令重定向它。<strong>确认 <code>Esc</code> 是「暂停交还」而不是「报错崩溃」</strong>。</p></blockquote><p><strong>第五步（选做）：查一下快速模式开关</strong></p><p>输入 <code>/fast</code> 按 Tab，看看提示。</p><blockquote><p><strong>预期</strong>：如果你的账户支持，会看到 <code>Fast mode ON</code> 和提示框旁的 <code>↯</code> 图标；再 <code>/fast</code> 一下关掉。如果你的账户/计划不支持或没开使用额度，会看到类似「fast mode 不可用」的提示——<strong>这一步是「能开就体验、不能开也正常」</strong>，不必强求。</p></blockquote><p>跑完这五步，本篇的核心控制手段你就<strong>全都亲手摸过一遍</strong>了。新手尤其要走一遍第二、三步——<strong>「在 Plan Mode 里它不动手、批准后才动手并切了模式」这个体感，看十遍文档不如自己按一次</strong>。</p><blockquote><p>💡 一句话总结：照着这五步把 <code>Shift+Tab</code> 切模式、Plan Mode 出方案与批准、<code>Esc</code> 喊停、<code>/fast</code> 开关<strong>连起来按一遍</strong>，每步对照「预期看到啥」自验；尤其第二三步，亲手体会「计划模式只走戏、批准才实拍且顺带切模式」。</p></blockquote><hr><h2 id="_08-小结" tabindex="-1">08 小结 <a class="header-anchor" href="#_08-小结" aria-label="Permalink to &quot;08 小结&quot;">​</a></h2><p>这一篇把「会话已经开起来之后，你手里那块控制台」铺开讲了一遍。<a href="./20-permissions">第 20 篇</a>给你的是权限那根缰绳，这一篇给你的是全套操纵杆。</p><p>把核心串起来回顾：</p><table tabindex="0"><thead><tr><th>你想干的事</th><th>控制手段</th><th>一句话关键点</th></tr></thead><tbody><tr><td>让它动手前少问 / 多问</td><td><code>Shift+Tab</code> 循环模式</td><td>默认三档，<code>auto</code>/<code>bypass</code> 满足条件才入列，<code>auto</code> 垫底</td></tr><tr><td>它跑偏了喊停重定向</td><td><code>Esc</code></td><td>暂停交还方向盘，已完成的保留</td></tr><tr><td>退回对话上一个点</td><td><code>Esc</code> <code>Esc</code>（空框时）</td><td>打开回退菜单，细节见<a href="./37-checkpoints">第 37 篇</a></td></tr><tr><td>中断 / 清输入 / 退出</td><td><code>Ctrl+C</code> / <code>Ctrl+D</code></td><td>空框第二下 <code>Ctrl+C</code> 就退，别乱连按</td></tr><tr><td>长命令丢后台</td><td><code>Ctrl+B</code></td><td>tmux 里要按两下</td></tr><tr><td>先出方案再动手</td><td>Plan Mode（<code>/plan</code>）</td><td>只走戏不实拍，批准时顺带选定权限模式</td></tr><tr><td>花钱买更快的 Opus</td><td><code>/fast</code></td><td>同质量、更贵、要开就会话一开始开</td></tr><tr><td>Vim 手势编辑输入</td><td><code>/config</code> → 编辑器模式</td><td>Vim 党锦上添花，新手可跳过</td></tr></tbody></table><p><strong>你现在应该能：</strong> 在一个跑起来的会话里游刃有余地操纵 Claude——<code>Shift+Tab</code> 切到合适的自主权档位、<code>Esc</code> 把跑偏的它一脚拽回来、用 Plan Mode 让陌生项目「先出方案你审完再动手」、按需要 <code>/fast</code> 拿速度、Vim 党还能用熟悉的手势编辑提示。<strong>说白了，你从「只会打字回车干等」，升级成了「全程手握操纵杆、随时能控」。</strong></p><p>整个第五组「系统配置与优化」走到这儿，配置文件、输出样式、钩子、CLI 标志、控制与模式都铺过了，你对 Claude Code「怎么配、怎么控」已经有了系统的把握。</p><hr><p>下一篇 <strong>36「斜杠命令（Slash Commands）」</strong>，把视线收回到那个最不起眼、却天天在用的小符号上——<code>/</code>。本篇里你已经敲过 <code>/plan</code>、<code>/fast</code>、<code>/config</code> 好几个斜杠命令了，但它们到底有多少、能不能自己造一个属于自己的 <code>/</code> 命令？想想看：<strong>那些你天天手打的固定流程，要是能压成一个 <code>/</code> 一键喊出来，会省多少事</strong>——下一篇见分晓。</p>',145)])])}const u=t(s,[["render",a]]);export{h as __pageData,u as default};
